+bool SimplifyCFGOpt::simplifySwitchOnCmpIntrinsic(SwitchInst *SI,
+                                                  IntrinsicInst *II,
+                                                  IRBuilder<> &Builder) {
+  if (!II->hasOneUse()) return false;
+  if (II->getIntrinsicID() != Intrinsic::ucmp &&
+      II->getIntrinsicID() != Intrinsic::scmp)
+    return false;
+
+  BasicBlock *DefaultDest = SI->getDefaultDest();
+  BasicBlock *LessDest = DefaultDest;
+  BasicBlock *EqualDest = DefaultDest;
+  BasicBlock *GreaterDest = DefaultDest;
+
+  for (auto Case : SI->cases()) {
+    int64_t V = Case.getCaseValue()->getSExtValue();
+    if (V == -1) LessDest = Case.getCaseSuccessor();
+    else if (V == 0) EqualDest = Case.getCaseSuccessor();
+    else if (V == 1) GreaterDest = Case.getCaseSuccessor();
+    else return false;
+  }
+
+  BasicBlock *Dest1 = LessDest;
+  BasicBlock *Dest2 = nullptr;
+  if (EqualDest != Dest1) Dest2 = EqualDest;
+  if (GreaterDest != Dest1 && GreaterDest != Dest2) {
+    if (!Dest2) Dest2 = GreaterDest;
+    else return false;
+  }
+  
+  if (!Dest2) return false;
+
+  ICmpInst::Predicate Pred;
+  bool IsSigned = II->getIntrinsicID() == Intrinsic::scmp;
+  BasicBlock *TrueDest;
+  BasicBlock *FalseDest;
+  
+  if (LessDest == EqualDest) {
+    Pred = IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+    TrueDest = GreaterDest;
+    FalseDest = LessDest;
+  } else if (EqualDest == GreaterDest) {
+    Pred = IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+    TrueDest = LessDest;
+    FalseDest = EqualDest;
+  } else if (LessDest == GreaterDest) {
+    Pred = ICmpInst::ICMP_EQ;
+    TrueDest = EqualDest;
+    FalseDest = LessDest;
+  } else {
+    return false;
+  }
+
+  Value *LHS = II->getArgOperand(0);
+  Value *RHS = II->getArgOperand(1);
+  Value *Cmp = Builder.CreateICmp(Pred, LHS, RHS);
+  
+  uint32_t TrueWeight = 0, FalseWeight = 0;
+  if (hasBranchWeightMD(*SI)) {
+    SmallVector<uint64_t, 8> Weights;
+    getBranchWeights(SI, Weights);
+    if (Weights.size() == 1 + SI->getNumCases()) {
+      for (auto Case : SI->cases()) {
+        int64_t V = Case.getCaseValue()->getSExtValue();
+        uint64_t W = Weights[Case.getSuccessorIndex()];
+        if ((V == -1 || V == 0) && FalseDest == LessDest && LessDest == EqualDest)
+          FalseWeight += W;
+        else if (V == 1 && TrueDest == GreaterDest && LessDest == EqualDest)
+          TrueWeight += W;
+        else if ((V == 0 || V == 1) && FalseDest == EqualDest && EqualDest == GreaterDest)
+          FalseWeight += W;
+        else if (V == -1 && TrueDest == LessDest && EqualDest == GreaterDest)
+          TrueWeight += W;
+        else if ((V == -1 || V == 1) && FalseDest == LessDest && LessDest == GreaterDest)
+          FalseWeight += W;
+        else if (V == 0 && TrueDest == EqualDest && LessDest == GreaterDest)
+          TrueWeight += W;
+      }
+      uint64_t DefaultWeight = Weights[0];
+      if (DefaultDest == TrueDest) TrueWeight += DefaultWeight;
+      if (DefaultDest == FalseDest) FalseWeight += DefaultWeight;
+    }
+  }
+
+    return simplifyTerminatorOnSelect(SI, Cmp, TrueDest, FalseDest, TrueWeight, FalseWeight);
+}
